var classification = $runner.getModuleResult("OpenAI_用件");
var desiredDate = $runner.getModuleResult("OpenAI_希望日");
var result = "";
if (classification === "変更キャンセル" && desiredDate === "ありません") {
    result = "キャンセル";
} else if (classification === "予約") {
    result = "予約_携帯";
} else {
    result = "変更確認_携帯";
}
$runner.setResult(result);

